const contacts = $input.all();
const form = $('Launch Campaign Form').first().json;
const results = [];
for (const item of contacts) {
  const r = item.json;
  const email = (r['Email'] || '').trim();
  const status = (r['Email Status'] || r['Status'] || '').trim().toLowerCase();
  if (email && (status === 'verified' || status === 'new lead')) {
    const firstName = (r['First Name'] || '').trim();
    const lastName = (r['Last Name'] || '').trim();
    const companyName = (r['Company Name'] || '').trim();
    const title = (r['Title'] || '').trim();
    const industry = (r['Industry'] || '').trim();
    const agencyName = (form['Your Agency Name'] || '').trim();
    const service = (form['Service You Are Selling'] || '').trim();
    const uvp = (form['Your Unique Value Proposition'] || '').trim();
    const senderEmail = (form['Your Sender Email'] || '').trim();
    const senderName = (form['Your Full Name'] || '').trim();
    const compCtx = [industry, r['# Employees'], r.Technologies].filter(Boolean).join(' | ');
    const loc = [r.City, r.Country].filter(Boolean).join(', ');
    const fullName = (firstName + ' ' + lastName).trim();
    results.push({ json: {
      // Space-keyed (for sheets)
      'Agency Name': agencyName, 'Service': service, 'UVP': uvp, 'Sender Email': senderEmail, 'Sender Name': senderName,
      'Email': email, 'First Name': firstName, 'Last Name': lastName, 'Company Name': companyName,
      'Title': title, 'Industry': industry, 'Website': r.Website || '',
      // camelCase (for prompts/code)
      agencyName, service, uvp, senderEmail, senderName,
      email, firstName, lastName, companyName, title, industry,
      fullName, companyContext: compCtx, location: loc
    }});
  }
}
return results;

return $input.all().map(item => {
  const lead = item.json;
  let score = 0;
  const title = (lead.title || lead.Title || '').toLowerCase();
  if (title.includes('ceo') || title.includes('founder') || title.includes('owner')) score += 40;
  else if (title.includes('vp') || title.includes('director')) score += 30;
  else score += 15;
  const emp = parseInt(String(lead.Employees || lead.numEmployees || '0').replace(/\D/g,''), 10) || 0;
  if (emp > 500) score += 30; else if (emp > 50) score += 20; else score += 10;
  score = Math.min(score, 100);
  const tier = score >= 60 ? 'premium' : 'standard';
  return { json: { ...lead, leadScore: score, tier, leadTier: tier.toUpperCase(), gptModel: tier === 'premium' ? 'gpt-4o' : 'gpt-4o-mini', 'Lead Score': score, 'Tier': tier.toUpperCase() } };
});

