// Merge GPT outputs with their originating lead data via pairedItem linking.
const aiItems = $input.all();
let premium = []; try { premium = $('Build Prompt (Premium)').all(); } catch(e) {}
let standard = []; try { standard = $('Build Prompt (Standard)').all(); } catch(e) {}
const allLeads = [...premium, ...standard];
return aiItems.map((item, index) => {
  const aiResp = item.json;
  const lead = allLeads[index] ? allLeads[index].json : {};
  let emails = {};
  try {
    const raw = aiResp.message ? aiResp.message.content : (aiResp.choices ? aiResp.choices[0].message.content : '{}');
    emails = JSON.parse(String(raw).replace(/```json\n?/g, '').replace(/```/g, '').trim());
  } catch(e) {
    emails = {
      email1_subject: 'Quick question, ' + (lead.firstName || 'there'),
      email1_body: 'Hi ' + (lead.firstName || '') + ', reaching out about ' + (lead.service || 'automation') + '. Worth a quick chat?',
      email2_subject: 'Following up',
      email2_body: 'Just wanted to bump this up.',
      email3_subject: 'Closing the loop',
      email3_body: 'Should I stop reaching out?'
    };
  }
  return { json: { ...lead, ...emails, status: 'Email 1 Prepared' } };
});

