const aiScores = $input.all();
let leads = [];
try { leads = $('Parse AI Emails & Merge').all(); } catch(e) {}
return aiScores.map((item, index) => {
  const scoreRaw = item.json;
  let scoreData = {};
  try {
    const content = scoreRaw.message?.content || scoreRaw.choices?.[0]?.message?.content || '{}';
    scoreData = JSON.parse(String(content).replace(/```json\n?/g,'').replace(/```/g,'').trim());
  } catch(e) { scoreData = { total: 35, verdict: 'SEND', notes: 'parse fallback' }; }
  const lead = leads[index] ? leads[index].json : {};
  return { json: {
    ...lead,
    'Quality Score': scoreData.total || 0,
    'Verdict': (scoreData.verdict || 'REVIEW').toUpperCase(),
    'Quality Notes': scoreData.notes || '',
    'Status': (scoreData.verdict || '').toUpperCase() === 'SEND' ? 'Ready' : 'In Review'
  } };
});

