// Collapse all leads to a single trigger item so Blacklist Lookup runs ONCE.
if ($itemIndex === 0) {
  return [{ json: { _blacklistTrigger: true } }];
}
return [];

// Collect blacklist emails from the single Blacklist Lookup read
const items = $input.all();
const blacklistEmails = items
  .filter(r => r.json && !r.json.error && !r.json._blacklistTrigger)
  .map(r => (r.json.Email || r.json.email || '').toLowerCase().trim())
  .filter(Boolean);

// Retrieve leads from Decision Dashboard Builder
let leads = [];
try { leads = $('Decision Dashboard Builder').all(); } catch(e) { leads = []; }

if (leads.length === 0) {
  return [{ json: { _noLeads: true, _blacklistEmails: [] } }];
}

return leads.map(leadItem => ({
  json: { ...leadItem.json, _blacklistEmails: blacklistEmails }
}));

// Filter out blacklisted leads and strip helper field
const clean = [];
for (const item of $input.all()) {
  const { _blacklistEmails, _noLeads, ...leadData } = item.json;
  if (_noLeads) continue;
  const blacklist = Array.isArray(_blacklistEmails) ? _blacklistEmails : [];
  const email = (leadData.Email || leadData.email || '').toLowerCase().trim();
  if (email && blacklist.includes(email)) continue;
  clean.push({ json: { ...leadData } });
}
return clean;

